struct BMP256HEADER
{
	short Id;
	long FSize, Ver, DataOffset, Unused, Width, Height;
	short WTF, BPP;
	long Compr; //0 for uncompressed, 1,2 for RLE
	long DataSize, XRes, YRes, PalSize, Unused2;
	char Palette[256][4];
};
#pragma pack(pop)

char const * LoadBMP256(char *Name, unsigned char Pal[256][3], unsigned char __far * ImgBody, int BodyArrayWidth, int MaxH)
{
	fstream f;
	unsigned long Line, W,H,W4, X;
	BMP256HEADER Head;

	f.open (Name, ios::in|ios::binary);
	f.read ((char*)&Head, sizeof (Head));
	if (f.fail()) return "Can't open file!";
	if (Head.Id!=0x4D42) return "Wrong BMP id! Not a BMP file?";
	if (Head.Compr) return "Compressed files are not supported for now!";
	if (Head.BPP!=8) return "Wrong bits per pixel! Expected to read 256-color image.";
//cout<<Head.PalSize<<endl;
	for (H=0; H<256; H++) {Pal[H][0]=Head.Palette[H][2];Pal[H][1]=Head.Palette[H][1];Pal[H][2]=Head.Palette[H][0];}

	H=Head.Height;
	W=Head.Width;
	if (!W||!H||W>BodyArrayWidth||H>MaxH) return ("Wrong image size!");
	W4=(W+3)&(~3);

	for (Line=0;Line<H;Line++)
	{
 f.seekg (Head.DataOffset+Line*W4, ios::beg);
 f.read (ImgBody+(H-Line-1)*BodyArrayWidth, W);
	}
	f.close();

	return NULL;
}

float TheFamousFastRSqRt (float Val)
{
	long i;
	float f=Val;

	i = *(long *)&f;
	i = 0x5f3759df - (i>>1);
	f = *(float *)&i;
	return f * (1.5 - Val*.5*f*f);
}

short LessFamousBhaskaraI_Sine_0_to_180deg(short Arg)	//Arg 512 = 180 deg.
{
	signed long Temp,Temp2;
	Temp=Temp2=Arg;
	Temp2=511-Temp2;
	Temp*=4096*Temp2;
	Temp/=327680-((signed long)Arg)*Temp2;
	return Temp;	//Sine X 1024
}

unsigned short X, Y;	//6 MSB = map tile, 6 bits = pixel inside a tile, 4 LSB = pixel fractions.
signed short Angle=0;	//+-32768 = +-180 deg.
signed short DX=1024, DY=0;	//cos and sin of Angle X 1024.
#define GRUDAK (12<<4)

int DoClipping (signed short StepX, signed short StepY)	//Wolf3d Clone
{
	unsigned short MinX, MaxX, MinY, MaxY;

	MinX = X-GRUDAK+StepX;
	MaxX = X+GRUDAK+StepX;
	MinY = Y-GRUDAK+StepY;
	MaxY = Y+GRUDAK+StepY;

	if (Map[MinY>>10][MinX>>10]|
 Map[MinY>>10][MaxX>>10]|
 Map[MaxY>>10][MinX>>10]|
 Map[MaxY>>10][MaxX>>10])
	{
 if (!StepX || !StepY) return 0;
 return DoClipping(StepX, 0) || DoClipping(0, StepY);
	}

	X+=StepX;
	Y+=StepY;
	return 1;
}

struct
{
	unsigned short X, Y;	//6 MSB = map tile, 6 bits = pixel inside a tile, 4 LSB = pixel fractions.
	signed short Rotation;	//+-32768 = +-180 deg.
} TestMob = {32<<10, 32<<10, 0};

void AnimateTestMob()
{
	short A_0_180, SpinX, SpinY;

	Map[(TestMob.Y-(32<<4))>>10][(TestMob.X-(32<<4))>>10]=0;
	Map[(TestMob.Y-(32<<4))>>10][(TestMob.X+(32<<4))>>10]=0;
	Map[(TestMob.Y+(32<<4))>>10][(TestMob.X-(32<<4))>>10]=0;
	Map[(TestMob.Y+(32<<4))>>10][(TestMob.X+(32<<4))>>10]=0;

	A_0_180 = TestMob.Rotation>>6;
	if (A_0_180>0) SpinY=LessFamousBhaskaraI_Sine_0_to_180deg(A_0_180);
	else SpinY=-LessFamousBhaskaraI_Sine_0_to_180deg(-A_0_180);
	A_0_180 = TestMob.Rotation+16384; //Native overflow to a correct angle.
	A_0_180 >>= 6;
	if (A_0_180>0) SpinX=LessFamousBhaskaraI_Sine_0_to_180deg(A_0_180);
	else SpinX=-LessFamousBhaskaraI_Sine_0_to_180deg(-A_0_180);
	TestMob.Rotation+=300;

	TestMob.X = (32<<10) + SpinX*4;
	TestMob.Y = (32<<10) + SpinY*4;

	Map[(TestMob.Y-(32<<4))>>10][(TestMob.X-(32<<4))>>10]=128;
	Map[(TestMob.Y-(32<<4))>>10][(TestMob.X+(32<<4))>>10]=128;
	Map[(TestMob.Y+(32<<4))>>10][(TestMob.X-(32<<4))>>10]=128;
	Map[(TestMob.Y+(32<<4))>>10][(TestMob.X+(32<<4))>>10]=128;
}

