static const char OmitMap[16]=
{
/* Size Flags	NeoGeo size code
1	0000000010000000	0x0
2	0000100010000000 0x1
3	0000100010001000 0x2
4	0010100010001000 0x3
5	0010100010001010 0x4
6	0010101010001010 0x5
7	0010101010101010 0x6
8	1010101010101010 0x7
9	1010101011101010 0x8
10	1011101011101010 0x9
11	1011101011101011 0xA
12	1011101111101011 0xB
13	1011101111101111 0xC
14	1111101111101111 0xD
15	1111101111111111 0xE
16	1111111111111111 0xF
	"Draw if Size > ..." */
0x07, 0x0D, 0x03, 0x09, 0x01, 0x0F, 0x05, 0x0B, 0x00, 0x08, 0x06, 0x0E, 0x02, 0x0C, 0x04, 0x0A
};

void BlitWallLikeTheNeoGeo (int XPos, int YPos, int XSize, int YSize, unsigned char __far *Column)
{	//No upscale. Downscale only. Max. 16 size X and 512 size Y. Y downscale is not accurate (written from scratch). X downscale is based on the NeoGeoDevWiki.
	if (YSize>256) YSize=256;
	for (int Y=0; Y<YSize; Y++)
	{
 int YSrc = (long)Y*256/(long)YSize;
 for (int X=0, XDst=0; X<16; X++)
 {
 if (OmitMap[X]<XSize)	//...or <= NeoGeo size code
 {
 if (XDst+XPos<320 && XDst+XPos>=0)	//AFAIK NeoGeo can auto-crop and auto-shingle sprites if they are set in the certain order
 Frame[Y+YPos][XDst+XPos] = Column[X + 16*YSrc];
 XDst++;
 }
 }
	}
}
void BlitMobLikeTheNeoGeo (int XPos, int YPos, int XSize, int YSize, unsigned char __far *Column)
{	//No upscale. Downscale only. Max. 16 size X and 512 size Y. Y downscale is not accurate (written from scratch). X downscale is based on the NeoGeoDevWiki.
	if (YSize>64) YSize=64;
	for (int Y=0; Y<YSize; Y++)
	{
 int YSrc = (long)Y*64/(long)YSize;
 for (int X=0, XDst=0; X<16; X++)
 {
 if (OmitMap[X]<XSize)	//...or <= NeoGeo size code
 {
 if (XDst+XPos<320 && XDst+XPos>=0)	//AFAIK NeoGeo can auto-crop and auto-shingle sprites if they are set in the certain order
 if (Column[X + 16*YSrc] != 0xF7)	//Doom transparent
 Frame[Y+YPos][XDst+XPos] = Column[X + 16*YSrc];
 XDst++;
 }
 }
	}
}

