static unsigned short ScaleF[320];

int ShingledReserve=0;

int AddToZBufferAndBlacklist (int Type, unsigned short CameraX, unsigned short CameraY, unsigned short RayX, unsigned short RayY, int Column, char WhichWall, float CosA)
{
	unsigned short DistToX, DistToY;
	unsigned long SqDist;
	int TextureHeight, TexturePos, Texture;

	if (Type>127)	//We hit the mob, not the wall (not always the mob itself, but one of it's "link cells"). So we add it to the drawing list, in order to place properly later.
	{
 float x1,x2,y1,y2;	//line
 float x0,y0;	//mob center
 float d;	//distance

 x1=RayX;
 x2=CameraX;
 y1=RayY;
 y2=CameraY;

 x0=TestMob.X;
 y0=TestMob.Y;

 d=(x2-x1)*(y1-y0) - (x1-x0)*(y2-y1);
 d*=TheFamousFastRSqRt( (x2-x1)*(x2-x1) + (y2-y1)*(y2-y1) );

// d+=(float)DemoSargWidth/2.0;
// ZBuff[0].Texture = d / 16.0;
// if (ZBuff[0].Texture>=0 && ZBuff[0].Texture<DemoSargWidth)	//ray passes inside the mob texture bounds
// {
 if (TestMob.X>CameraX) DistToX = TestMob.X - CameraX; else DistToX = CameraX - TestMob.X;
 if (TestMob.Y>CameraY) DistToY = TestMob.Y - CameraY; else DistToY = CameraY - TestMob.Y;

 SqDist = DistToX;
 SqDist *= SqDist;
 SqDist += ((long)DistToY) * ((long)DistToY);
// ZBuff[0].TextureHeight = 65536.0 * TheFamousFastRSqRt (SqDist/16);

// ZBuff[0].TextureHeight = (long)(ScaleF[Column])*(long)(ZBuff[0].TextureHeight)/2048/4;
// ZBuff[0].TexturePos = 100-ZBuff[0].TextureHeight/8;
// }

 TextureHeight = 32768.0 * TheFamousFastRSqRt (SqDist/16);
 TextureHeight = (long)(ScaleF[Column*5+2])*(long)TextureHeight/2048/24;

 d/=4.0;	//in texture pixels
 d+=32.0;	//zero if ray hits exactly the leftmost column of the mob
 d*=TextureHeight;
 d/=64.0;	//in screen pixels

 if (MobCount<8)
 {
 for (int i=0; i<4;i++)
 {
 MobTileList[MobCount][i].SqDist = SqDist;
 MobTileList[MobCount][i].X=Column*5+2 -d + TextureHeight*i/4;
 MobTileList[MobCount][i].Y=100-TextureHeight/5;
 MobTileList[MobCount][i].XSize=TextureHeight*(i+1)/4 - TextureHeight*i/4;
 MobTileList[MobCount][i].YSize=TextureHeight;
 MobTileList[MobCount][i].ImgPtr=MobColumns[i][0];
 }

 MobCount++;
 } // else sacrifice the most distant one

 return Type; //Blacklist this mob
	}

	switch (WhichWall)	//In the most generic case, the wall block can have all four textures set independently. In Wolf3D, L+R and U+D were different (some are darker, also day/night and lift switch/wall). Here, all texture are the same but must be calculated in the proper direction.
	{
 case 'L':
 Texture = 255-RayY%1024/4;
 break;
 case 'R':
 Texture = RayY%1024/4;
 break;
 case 'U':
 Texture = 255-RayX%1024/4;
 break;
 case 'D':
 Texture = RayX%1024/4;
 break;
 default: Texture = 0;
	}

	if (RayX>CameraX) DistToX = RayX - CameraX; else DistToX = CameraX - RayX;
	if (RayY>CameraY) DistToY = RayY - CameraY; else DistToY = CameraY - RayY;
	SqDist = DistToX;
	SqDist *= SqDist;
	SqDist += ((long)DistToY) * ((long)DistToY);
	TextureHeight = 65536.0 * TheFamousFastRSqRt (SqDist/16);

	if (ModeVGA == 5)	//Perfect, literal, 320 ray VGA
	{
 TextureHeight = (long)(ScaleF[Column])*(long)TextureHeight/2048/24;
 for (int y=0; y<200; y++) //In DOSBox, this loop takes... forever.
 {
 int TexY;
 if (TextureHeight) TexY = (signed long)(y-100)*256L / (signed long)(TextureHeight) + 128;
 else TexY=256-128*(y==100);
 if (TexY<0 || TexY>255) Frame[y][Column]=0;
 else Frame[y][Column]=TestWall[TexY][Texture];
 }
	} else {
 if (Mode2Dfx>1)	//Optimal NeoGeo
 {
 TextureHeight = (long)(ScaleF[Column*5+2])*(long)TextureHeight/2048/24;
 float Min=256;
 int MinX=0, Best;
 long TextureWidth = 16 * TextureHeight * CosA / 128;
if (TextureHeight>200) TextureHeight=200;	//Debug! Should be 1..256 (up to 1:1) but it'll require cropping
 unsigned char __far *Col;
 if (TextureWidth>18 || TextureWidth<3)	//Two repeating pixels are still OK
 {
 Col = ShiftedColumnsBl[Texture/16][0];	//Nothing to optimize here -- it'll be blurry either way
 MinX = ShingledReserve;
 }
 else {
 for (int x=-2; x<=ShingledReserve; x++)
 {
 float Offset = (float)x * 128.0/(float)TextureHeight / CosA;
 float Candidate = (float)Texture+Offset;
 int Nearest4 = Candidate+2.5;	//+2 and rounding
 Nearest4&=~3;
 float Err = fabs((float)Nearest4-Candidate);
 if (Min>Err) {Min=Err;MinX=x;Best=Nearest4;}
 }
 switch (Best%16/4)
 {
 case 0: Col = ShiftedColumns00[Best/16][0]; break;
 case 1: Col = ShiftedColumns04[Best/16][0]; break;
 case 2: Col = ShiftedColumns08[Best/16][0]; break;
 case 3: Col = ShiftedColumns12[Best/16][0]; break;
 }
 }
 if (TextureWidth<5) TextureWidth=5;
 ShingledReserve = MinX+TextureWidth-5;
 if (ShingledReserve>2) ShingledReserve=2;

 if (Mode2Dfx>2)
 {
 WallTileList[Column].SqDist = SqDist;
 WallTileList[Column].X = Column*5+MinX;
 WallTileList[Column].Y = 100-TextureHeight/2;
 WallTileList[Column].XSize = TextureWidth;
 WallTileList[Column].YSize = TextureHeight;
 WallTileList[Column].ImgPtr = Col;
 }
 else BlitWallLikeTheNeoGeo (Column*5+MinX, 100-TextureHeight/2, TextureWidth, TextureHeight, Col);
 }
 else if (Mode2Dfx)	//Trivial (Naive) NeoGeo
 {
 TextureHeight = (long)(ScaleF[Column*5+2])*(long)TextureHeight/2048/24;
 long TextureWidth = 16 * TextureHeight * CosA / 128;
if (TextureHeight>200) TextureHeight=200;	//Debug! Should be 1..256 (up to 1:1) but it'll require cropping
 unsigned char __far *Col;
 switch (Texture%16/4)
 {
 case 0: Col = ShiftedColumns00[Texture/16][0]; break;
 case 1: Col = ShiftedColumns04[Texture/16][0]; break;
 case 2: Col = ShiftedColumns08[Texture/16][0]; break;
 case 3: Col = ShiftedColumns12[Texture/16][0]; break;
 }
 if (TextureWidth>18 || TextureWidth<3)	//Two repeating pixels are still OK
 Col = ShiftedColumnsBl[Texture/16][0];

 if (TextureWidth<5)
 BlitWallLikeTheNeoGeo (Column*5, 100-TextureHeight/2, 5 , TextureHeight, Col);
 else	BlitWallLikeTheNeoGeo (Column*5, 100-TextureHeight/2, TextureWidth, TextureHeight, Col);
 } else { //Unrestricted sprites
 TextureHeight = (long)(ScaleF[Column*5+2])*(long)TextureHeight/2048/24;
 for (int x=-2; x<=2; x++)
 {
 float Offset = (float)x * 128.0/(float)TextureHeight / CosA;
 int TexCol = Texture+Offset;
 TexCol %= 256;
 for (int y=0; y<200; y++)
 {
 int TexY;
 if (TextureHeight) TexY = (signed long)(y-100)*256L / (signed long)(TextureHeight) + 128;
 else TexY=256-128*(y==100);
 if (TexY<0 || TexY>255) Frame[y][Column*5+2+x]=0;
 else Frame[y][Column*5+2+x]=TestWall[TexY][TexCol];
 }
 }
 }
	}

	return 0;	// 0 is for "blacklist everything" (ray hits an opaque texture and terminates).
}

